CREATE OR REPLACE FUNCTION quote_ut.test_article_search()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_result jsonb;
  v_item jsonb;
BEGIN
  -- Test: returns jsonb array (not null)
  v_result := quote.article_search('');
  RETURN NEXT ok(v_result IS NOT NULL, 'search returns non-null');
  RETURN NEXT ok(jsonb_typeof(v_result) = 'array', 'search returns array');

  -- Test: with search filter
  v_result := quote.article_search('bois');
  RETURN NEXT ok(jsonb_typeof(v_result) = 'array', 'filtered search returns array');

  -- Test: items have required keys (value, label)
  IF jsonb_array_length(v_result) > 0 THEN
    v_item := v_result->0;
    RETURN NEXT ok(v_item ? 'value', 'item has value key');
    RETURN NEXT ok(v_item ? 'label', 'item has label key');
    RETURN NEXT ok(v_item ? 'detail', 'item has detail key');
  ELSE
    RETURN NEXT skip('no articles in stock, skipping structure checks');
    RETURN NEXT skip('no articles in stock');
    RETURN NEXT skip('no articles in stock');
  END IF;

  -- Test: nonsense search returns empty array
  v_result := quote.article_search('zzzzxyznonexistent');
  RETURN NEXT is(jsonb_array_length(v_result), 0, 'nonsense search returns empty');
END;
$function$;
COMMENT ON FUNCTION quote_ut.test_article_search() IS 'Test article_search returns valid jsonb for pgv.select_search()';

CREATE OR REPLACE FUNCTION quote_ut.test_delete_constraints()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int;
  v_client_id int;
BEGIN
  UPDATE project.chantier SET devis_id = NULL WHERE devis_id IS NOT NULL;
  DELETE FROM quote.ligne;
  DELETE FROM quote.facture;
  DELETE FROM quote.devis;

  SELECT id INTO v_client_id FROM crm.client LIMIT 1;

  -- Devis non-brouillon ne peut pas être supprimé
  PERFORM quote.post_devis_save(jsonb_build_object('client_id', v_client_id, 'objet', 'Test delete'));
  SELECT id INTO v_id FROM quote.devis ORDER BY id DESC LIMIT 1;
  PERFORM quote.post_devis_envoyer(jsonb_build_object('id', v_id));

  RETURN NEXT throws_ok(
    format('SELECT quote.post_devis_supprimer(''{"id":%s}''::jsonb)', v_id),
    'Seuls les brouillons peuvent être supprimés'
  );

  -- Devis brouillon peut être supprimé
  PERFORM quote.post_devis_save(jsonb_build_object('client_id', v_client_id, 'objet', 'Brouillon'));
  SELECT id INTO v_id FROM quote.devis WHERE statut = 'brouillon' ORDER BY id DESC LIMIT 1;
  PERFORM quote.post_devis_supprimer(jsonb_build_object('id', v_id));
  RETURN NEXT is((SELECT count(*)::int FROM quote.devis WHERE id = v_id), 0, 'Brouillon supprimé');

  -- Facture envoyée ne peut pas être supprimée (immutabilité légale)
  PERFORM quote.post_facture_save(jsonb_build_object('client_id', v_client_id, 'objet', 'Test immuable'));
  SELECT id INTO v_id FROM quote.facture ORDER BY id DESC LIMIT 1;
  PERFORM quote.post_facture_envoyer(jsonb_build_object('id', v_id));

  RETURN NEXT throws_ok(
    format('SELECT quote.post_facture_supprimer(''{"id":%s}''::jsonb)', v_id),
    'Seuls les brouillons peuvent être supprimés'
  );

  UPDATE project.chantier SET devis_id = NULL WHERE devis_id IS NOT NULL;
  DELETE FROM quote.ligne;
  DELETE FROM quote.facture;
  DELETE FROM quote.devis;
END;
$function$;
COMMENT ON FUNCTION quote_ut.test_delete_constraints() IS 'Test contraintes de suppression (brouillon only, immutabilité facture)';

CREATE OR REPLACE FUNCTION quote_ut.test_devis_facturer()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_devis_id int;
  v_facture_id int;
  v_client_id int;
  v_nb_lignes_d int;
  v_nb_lignes_f int;
  v_ttc_d numeric(12,2);
  v_ttc_f numeric(12,2);
BEGIN
  UPDATE project.chantier SET devis_id = NULL WHERE devis_id IS NOT NULL;
  DELETE FROM quote.ligne;
  DELETE FROM quote.facture;
  DELETE FROM quote.devis;

  SELECT id INTO v_client_id FROM crm.client LIMIT 1;

  -- Créer devis + lignes
  PERFORM quote.post_devis_save(jsonb_build_object('client_id', v_client_id, 'objet', 'Travaux salle de bain'));
  SELECT id INTO v_devis_id FROM quote.devis ORDER BY id DESC LIMIT 1;

  PERFORM quote.post_ligne_ajouter(jsonb_build_object('devis_id', v_devis_id, 'description', 'Main oeuvre', 'quantite', 8, 'unite', 'h', 'prix_unitaire', 45, 'tva_rate', 10));
  PERFORM quote.post_ligne_ajouter(jsonb_build_object('devis_id', v_devis_id, 'description', 'Fournitures', 'quantite', 1, 'unite', 'forfait', 'prix_unitaire', 350, 'tva_rate', 20));

  -- Facturer un brouillon -> erreur
  RETURN NEXT throws_ok(
    format('SELECT quote.post_devis_facturer(''{"id":%s}''::jsonb)', v_devis_id),
    'Seuls les devis acceptés peuvent être facturés'
  );

  -- Cycle: envoyer -> accepter -> facturer
  PERFORM quote.post_devis_envoyer(jsonb_build_object('id', v_devis_id));
  PERFORM quote.post_devis_accepter(jsonb_build_object('id', v_devis_id));
  PERFORM quote.post_devis_facturer(jsonb_build_object('id', v_devis_id));

  SELECT id INTO v_facture_id FROM quote.facture WHERE devis_id = v_devis_id;
  RETURN NEXT isnt(v_facture_id, NULL, 'Facture créée depuis devis');

  -- Vérifier que les lignes ont été copiées
  SELECT count(*)::int INTO v_nb_lignes_d FROM quote.ligne WHERE devis_id = v_devis_id;
  SELECT count(*)::int INTO v_nb_lignes_f FROM quote.ligne WHERE facture_id = v_facture_id;
  RETURN NEXT is(v_nb_lignes_f, v_nb_lignes_d, 'Lignes copiées dans la facture');

  -- Vérifier montants identiques
  SELECT sum(round(quantite * prix_unitaire, 2) + round(quantite * prix_unitaire * tva_rate / 100, 2))
    INTO v_ttc_d FROM quote.ligne WHERE devis_id = v_devis_id;
  SELECT sum(round(quantite * prix_unitaire, 2) + round(quantite * prix_unitaire * tva_rate / 100, 2))
    INTO v_ttc_f FROM quote.ligne WHERE facture_id = v_facture_id;
  RETURN NEXT is(v_ttc_f, v_ttc_d, 'TTC devis = TTC facture');

  UPDATE project.chantier SET devis_id = NULL WHERE devis_id IS NOT NULL;
  DELETE FROM quote.ligne;
  DELETE FROM quote.facture;
  DELETE FROM quote.devis;
END;
$function$;
COMMENT ON FUNCTION quote_ut.test_devis_facturer() IS 'Test conversion devis accepté -> facture avec copie des lignes';

CREATE OR REPLACE FUNCTION quote_ut.test_devis_lifecycle()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int;
  v_client_id int;
BEGIN
  UPDATE project.chantier SET devis_id = NULL WHERE devis_id IS NOT NULL;
  DELETE FROM quote.ligne;
  DELETE FROM quote.facture;
  DELETE FROM quote.devis;

  SELECT id INTO v_client_id FROM crm.client LIMIT 1;

  -- Créer un brouillon via API
  PERFORM quote.post_devis_save(jsonb_build_object('client_id', v_client_id, 'objet', 'Test lifecycle'));
  SELECT id INTO v_id FROM quote.devis ORDER BY id DESC LIMIT 1;

  RETURN NEXT is((SELECT statut FROM quote.devis WHERE id = v_id), 'brouillon', 'Nouveau devis = brouillon');

  -- brouillon -> envoye
  PERFORM quote.post_devis_envoyer(jsonb_build_object('id', v_id));
  RETURN NEXT is((SELECT statut FROM quote.devis WHERE id = v_id), 'envoye', 'Transition brouillon -> envoye');

  -- envoye -> accepte
  PERFORM quote.post_devis_accepter(jsonb_build_object('id', v_id));
  RETURN NEXT is((SELECT statut FROM quote.devis WHERE id = v_id), 'accepte', 'Transition envoye -> accepte');

  -- Transition invalide : accepte -> envoye
  RETURN NEXT throws_ok(
    format('SELECT quote.post_devis_envoyer(''{"id":%s}''::jsonb)', v_id),
    'Transition invalide: accepte -> envoye'
  );

  -- Test refus: nouveau brouillon -> envoye -> refuse
  PERFORM quote.post_devis_save(jsonb_build_object('client_id', v_client_id, 'objet', 'Test refus'));
  SELECT id INTO v_id FROM quote.devis ORDER BY id DESC LIMIT 1;

  PERFORM quote.post_devis_envoyer(jsonb_build_object('id', v_id));
  PERFORM quote.post_devis_refuser(jsonb_build_object('id', v_id));
  RETURN NEXT is((SELECT statut FROM quote.devis WHERE id = v_id), 'refuse', 'Transition envoye -> refuse');

  UPDATE project.chantier SET devis_id = NULL WHERE devis_id IS NOT NULL;
  DELETE FROM quote.ligne;
  DELETE FROM quote.facture;
  DELETE FROM quote.devis;
END;
$function$;
COMMENT ON FUNCTION quote_ut.test_devis_lifecycle() IS 'Test des transitions de statut devis';

CREATE OR REPLACE FUNCTION quote_ut.test_facture_lifecycle()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int;
  v_client_id int;
BEGIN
  UPDATE project.chantier SET devis_id = NULL WHERE devis_id IS NOT NULL;
  DELETE FROM quote.ligne;
  DELETE FROM quote.facture;
  DELETE FROM quote.devis;

  SELECT id INTO v_client_id FROM crm.client LIMIT 1;

  PERFORM quote.post_facture_save(jsonb_build_object('client_id', v_client_id, 'objet', 'Test lifecycle'));
  SELECT id INTO v_id FROM quote.facture ORDER BY id DESC LIMIT 1;

  RETURN NEXT is((SELECT statut FROM quote.facture WHERE id = v_id), 'brouillon', 'Nouvelle facture = brouillon');

  -- brouillon -> envoyee
  PERFORM quote.post_facture_envoyer(jsonb_build_object('id', v_id));
  RETURN NEXT is((SELECT statut FROM quote.facture WHERE id = v_id), 'envoyee', 'Transition brouillon -> envoyee');

  -- envoyee -> payee
  PERFORM quote.post_facture_payer(jsonb_build_object('id', v_id));
  RETURN NEXT is((SELECT statut FROM quote.facture WHERE id = v_id), 'payee', 'Transition envoyee -> payee');
  RETURN NEXT isnt((SELECT paid_at FROM quote.facture WHERE id = v_id), NULL, 'paid_at renseigné');

  -- Transition invalide
  RETURN NEXT throws_ok(
    format('SELECT quote.post_facture_envoyer(''{"id":%s}''::jsonb)', v_id),
    'Transition invalide: payee -> envoyee'
  );

  -- Suppression non-brouillon impossible
  RETURN NEXT throws_ok(
    format('SELECT quote.post_facture_supprimer(''{"id":%s}''::jsonb)', v_id),
    'Seuls les brouillons peuvent être supprimés'
  );

  UPDATE project.chantier SET devis_id = NULL WHERE devis_id IS NOT NULL;
  DELETE FROM quote.ligne;
  DELETE FROM quote.facture;
  DELETE FROM quote.devis;
END;
$function$;
COMMENT ON FUNCTION quote_ut.test_facture_lifecycle() IS 'Test des transitions de statut facture';

