CREATE OR REPLACE FUNCTION quote_ut.test_ligne_totals()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int;
  v_client_id int;
  v_ht numeric(12,2);
  v_tva numeric(12,2);
  v_ttc numeric(12,2);
BEGIN
  UPDATE project.chantier SET devis_id = NULL WHERE devis_id IS NOT NULL;
  DELETE FROM quote.ligne;
  DELETE FROM quote.facture;
  DELETE FROM quote.devis;

  SELECT id INTO v_client_id FROM crm.client LIMIT 1;

  PERFORM quote.post_devis_save(jsonb_build_object('client_id', v_client_id, 'objet', 'Test totaux'));
  SELECT id INTO v_id FROM quote.devis ORDER BY id DESC LIMIT 1;

  -- 3h à 45.50 EUR, TVA 10%
  PERFORM quote.post_ligne_ajouter(jsonb_build_object(
    'devis_id', v_id, 'description', 'Main oeuvre',
    'quantite', 3, 'unite', 'h', 'prix_unitaire', 45.50, 'tva_rate', 10
  ));
  -- 2.5 m2 à 35 EUR, TVA 20%
  PERFORM quote.post_ligne_ajouter(jsonb_build_object(
    'devis_id', v_id, 'description', 'Carrelage',
    'quantite', 2.5, 'unite', 'm2', 'prix_unitaire', 35, 'tva_rate', 20
  ));

  -- Calculer via SQL direct (arrondi par ligne) — pas d'appel cross-schema aux _helpers
  SELECT sum(round(quantite * prix_unitaire, 2)) INTO v_ht
    FROM quote.ligne WHERE devis_id = v_id;
  SELECT sum(round(quantite * prix_unitaire * tva_rate / 100, 2)) INTO v_tva
    FROM quote.ligne WHERE devis_id = v_id;
  v_ttc := v_ht + v_tva;

  -- HT: round(3*45.50, 2) + round(2.5*35, 2) = 136.50 + 87.50 = 224.00
  RETURN NEXT is(v_ht, 224.00::numeric(12,2), 'Total HT = 224.00');

  -- TVA: round(3*45.50*10/100, 2) + round(2.5*35*20/100, 2) = 13.65 + 17.50 = 31.15
  RETURN NEXT is(v_tva, 31.15::numeric(12,2), 'Total TVA = 31.15 (arrondi par ligne)');

  -- TTC = HT + TVA
  RETURN NEXT is(v_ttc, 255.15::numeric(12,2), 'Total TTC = 255.15');

  UPDATE project.chantier SET devis_id = NULL WHERE devis_id IS NOT NULL;
  DELETE FROM quote.ligne;
  DELETE FROM quote.devis;
END;
$function$;
COMMENT ON FUNCTION quote_ut.test_ligne_totals() IS 'Test calcul des totaux HT/TVA/TTC avec arrondi par ligne';

CREATE OR REPLACE FUNCTION quote_ut.test_next_numero()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_num1 text;
  v_num2 text;
  v_year text := to_char(now(), 'YYYY');
  v_client_id int;
BEGIN
  -- Cleanup (respect FK order)
  UPDATE project.chantier SET devis_id = NULL WHERE devis_id IS NOT NULL;
  DELETE FROM quote.ligne;
  DELETE FROM quote.facture;
  DELETE FROM quote.devis;

  SELECT id INTO v_client_id FROM crm.client LIMIT 1;

  -- Créer un premier devis via post_devis_save
  PERFORM quote.post_devis_save(jsonb_build_object('client_id', v_client_id, 'objet', 'Test 1'));
  SELECT numero INTO v_num1 FROM quote.devis ORDER BY id DESC LIMIT 1;
  RETURN NEXT is(v_num1, 'DEV-' || v_year || '-001', 'Premier devis = 001');

  -- Deuxième devis
  PERFORM quote.post_devis_save(jsonb_build_object('client_id', v_client_id, 'objet', 'Test 2'));
  SELECT numero INTO v_num2 FROM quote.devis ORDER BY id DESC LIMIT 1;
  RETURN NEXT is(v_num2, 'DEV-' || v_year || '-002', 'Deuxième devis = 002');

  -- Première facture
  PERFORM quote.post_facture_save(jsonb_build_object('client_id', v_client_id, 'objet', 'Facture 1'));
  SELECT numero INTO v_num1 FROM quote.facture ORDER BY id DESC LIMIT 1;
  RETURN NEXT is(v_num1, 'FAC-' || v_year || '-001', 'Première facture = 001');

  -- Test MAX+1 robustesse: supprimer le premier devis, le suivant doit être 003
  DELETE FROM quote.devis WHERE numero = 'DEV-' || v_year || '-001';
  PERFORM quote.post_devis_save(jsonb_build_object('client_id', v_client_id, 'objet', 'Test 3'));
  SELECT numero INTO v_num1 FROM quote.devis ORDER BY id DESC LIMIT 1;
  RETURN NEXT is(v_num1, 'DEV-' || v_year || '-003', 'Après suppression = 003 (MAX+1, pas count)');

  -- Cleanup
  UPDATE project.chantier SET devis_id = NULL WHERE devis_id IS NOT NULL;
  DELETE FROM quote.ligne;
  DELETE FROM quote.facture;
  DELETE FROM quote.devis;
END;
$function$;
COMMENT ON FUNCTION quote_ut.test_next_numero() IS 'Test numérotation séquentielle DEV/FAC via API publique';

CREATE OR REPLACE FUNCTION quote_ut.test_post_devis_dupliquer()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_client_id int;
  v_devis_id int;
  v_new_id int;
  v_count int;
BEGIN
  -- cleanup
  UPDATE project.chantier SET devis_id = NULL WHERE devis_id IS NOT NULL;
  DELETE FROM quote.ligne;
  DELETE FROM quote.facture;
  DELETE FROM quote.devis;

  -- use existing client
  SELECT id INTO v_client_id FROM crm.client LIMIT 1;

  INSERT INTO quote.devis (numero, client_id, objet, statut)
    VALUES ('DEV-2099-001', v_client_id, 'Devis original', 'envoye')
    RETURNING id INTO v_devis_id;
  INSERT INTO quote.ligne (devis_id, description, quantite, prix_unitaire, tva_rate)
    VALUES (v_devis_id, 'Ligne A', 2, 100.00, 20.00),
           (v_devis_id, 'Ligne B', 1, 50.00, 5.50);

  -- duplicate (function uses 'id' key)
  PERFORM quote.post_devis_dupliquer(jsonb_build_object('id', v_devis_id));

  -- new devis created
  SELECT id INTO v_new_id FROM quote.devis WHERE id <> v_devis_id AND client_id = v_client_id;
  RETURN NEXT ok(v_new_id IS NOT NULL, 'duplicate devis created');

  -- statut = brouillon
  RETURN NEXT is(
    (SELECT statut FROM quote.devis WHERE id = v_new_id),
    'brouillon', 'duplicate is brouillon');

  -- lignes copied
  SELECT count(*) INTO v_count FROM quote.ligne WHERE devis_id = v_new_id;
  RETURN NEXT is(v_count, 2, 'lignes copied');

  -- different numero
  RETURN NEXT isnt(
    (SELECT numero FROM quote.devis WHERE id = v_new_id),
    'DEV-2099-001', 'different numero');

  -- error on missing devis
  RETURN NEXT throws_ok(
    'SELECT quote.post_devis_dupliquer(''{"id": 999999}''::jsonb)',
    'P0001', NULL, 'error on missing devis');

  -- cleanup
  UPDATE project.chantier SET devis_id = NULL WHERE devis_id IS NOT NULL;
  DELETE FROM quote.ligne;
  DELETE FROM quote.facture;
  DELETE FROM quote.devis;
END;
$function$;
COMMENT ON FUNCTION quote_ut.test_post_devis_dupliquer() IS 'Test devis duplication feature';

